plt.title('Evolución de f1_micro para distintos valores de max_features')
plt.legend()
plt.show()

best_max_features, best_f1_micro = max(zip(max_features_values, scores), key=lambda t:t[1])
print(f"Mejor valor max_features={best_max_features} f1_micro={best_f1_micro}.")

